import { createContext, useContext } from "react";

//#region src/lib/components/BraidProvider/BraidThemeContext.ts
const BraidThemeContext = createContext(null);
const useBraidTheme = () => {
	const braidTheme = useContext(BraidThemeContext);
	if (braidTheme === null) throw new Error("No Braid theme available on context");
	return braidTheme;
};

//#endregion
export { BraidThemeContext, useBraidTheme };